import { Component, signal, computed } from '@angular/core';

@Component({
  selector: 'app-root',
  template: `
    <h1>{{ count() }}</h1>
    <button (click)="increment()">Increment</button>
  `,
})
export class AppComponent {
  count = signal(0);
  double = computed(() => this.count() * 2);

  increment() {
    this.count.update(c => c + 1);
  }
}
